// Simulating the LLVM optimization logic
#include <iostream>
#include <cstdint>

// Check the range computation logic
int main() {
    // Test case:
    // (icmp eq X, 127) | (icmp eq (X & -32), 128)
    // => "X is 127, OR lower 5 bits of X are 0 and the rest equals 4"
    // => "X is in [127, 159]"
    // 
    // 127 = 0x7F = 0b01111111
    // 128 = 0x80 = 0b10000000
    // -32 = 0xFFFFFFE0 = clear lower 5 bits
    // 
    // X = 127 satisfies first condition
    // X & -32 = 128 means X in [128, 159] (128 | 0-31)
    // So combined range is [127, 159]

    int32_t C1 = 127;
    int32_t C2Val = 128;
    int32_t Mask = -32;

    std::cout << "C1 = " << C1 << std::endl;
    std::cout << "C2Val = " << C2Val << std::endl;
    std::cout << "Mask = 0x" << std::hex << (uint32_t)Mask << std::dec << std::endl;

    std::cout << "Range 1: [" << C1 << ", " << C1 << "]" << std::endl;

    // Lower2 = C2Val
    // Upper2 = C2Val | (~Mask)
    // CR2(Lower2, Upper2 + 1)
    int32_t Lower2 = C2Val;
    int32_t Upper2 = C2Val | (~Mask);
    std::cout << "Lower2 = " << Lower2 << std::endl;
    std::cout << "Upper2 = " << Upper2 << " (C2Val | ~Mask)" << std::endl;
    std::cout << "Range 2: [" << Lower2 << ", " << Upper2 << "]" << std::endl;

    // The union should be [127, 159]
    // This should become (uint)(x - 127) < 33
    // or (x - 127) u< 33
    std::cout << "\nExpected: (unsigned)(x - 127) < 33" << std::endl;
    std::cout << "which is: add i32 x, -127, then icmp ult, 33" << std::endl;

    return 0;
}
EOF
