cd /root/auto-opt/utils/llvm-152948 && cat <<'EOF' | python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp 1354 1354

  // Handle the commuted case: (icmp eq (X & Mask), C2) | (icmp eq X, C1)
  // where C2 == C1 + 1 and C2 has no bits outside Mask.
  if (!IsAnd && Pred1 == ICmpInst::ICMP_EQ && Pred2 == ICmpInst::ICMP_EQ) {
    Value *X1;
    const APInt *Mask, *C1Val;
    // Check if ICmp1 is of the form (X & Mask) == C1
    if (match(V1, m_And(m_Value(X1), m_APInt(Mask))) &&
        match(ICmp1->getOperand(1), m_APInt(C1Val)) &&
        X1 == V2 && (*C1Val & ~*Mask) == 0 && *C2 + 1 == *C1Val) {
      ConstantRange CR2 = ConstantRange::makeExactICmpRegion(Pred2, *C2);
      APInt Lower1 = *C1Val;
      APInt Upper1 = *C1Val | (~*Mask);
      ConstantRange CR1(Lower1, Upper1 + 1);

      if (std::optional<ConstantRange> CR = CR1.exactUnionWith(CR2)) {
        CmpInst::Predicate NewPred;
        APInt NewC, Offset;
        CR->getEquivalentICmp(NewPred, NewC, Offset);
        Type *Ty = V2->getType();
        Value *NewV = V2;
        if (Offset != 0)
          NewV = Builder.CreateAdd(NewV, ConstantInt::get(Ty, Offset));
        return Builder.CreateICmp(NewPred, NewV, ConstantInt::get(Ty, NewC));
      }
    }
  }

EOF

