  // Handle the case of (icmp eq X, C1) | (icmp eq (X & Mask), C2)
  // where C2 == C1 + 1 and C2 has no bits outside Mask.
  // This is equivalent to checking if X is in [C1, C2 | ~Mask].
  if (!IsAnd && Pred1 == ICmpInst::ICMP_EQ && Pred2 == ICmpInst::ICMP_EQ) {
    auto TryMatchPattern = [&](Value *LVal, Value *RVal, const APInt *LC,
                               const APInt *RC, ICmpInst *LCmp,
                               ICmpInst *RCmp) -> Value * {
      Value *X2;
      const APInt *Mask, *C2Val;
      // Check if RCmp is of the form (X & Mask) == C2
      if (match(RVal, m_And(m_Value(X2), m_APInt(Mask))) &&
          match(RCmp->getOperand(1), m_APInt(C2Val)) && X2 == LVal &&
          (*C2Val & ~*Mask) == 0 && *C2Val == *LC + 1) {
        ConstantRange CR1 = ConstantRange::makeExactICmpRegion(
            ICmpInst::ICMP_EQ, *LC);
        APInt Lower2 = *C2Val;
        APInt Upper2 = *C2Val | (~*Mask);
        ConstantRange CR2(Lower2, Upper2 + 1);
        if (std::optional<ConstantRange> CR = CR1.exactUnionWith(CR2)) {
          CmpInst::Predicate NewPred;
          APInt NewC, Offset;
          CR->getEquivalentICmp(NewPred, NewC, Offset);
          Type *Ty = LVal->getType();
          Value *NewV = LVal;
          if (Offset != 0)
            NewV = Builder.CreateAdd(NewV, ConstantInt::get(Ty, Offset));
          return Builder.CreateICmp(NewPred, NewV, ConstantInt::get(Ty, NewC));
        }
      }
      return nullptr;
    };
    if (Value *V = TryMatchPattern(V1, V2, C1, C2, ICmp1, ICmp2))
      return V;
    if (Value *V = TryMatchPattern(V2, V1, C2, C1, ICmp2, ICmp1))
      return V;
  }

EOF"}

